// length nümunəsi
const text = 'Salam, Dünya!';
console.log(text.length); // 13
// Çıxış:
// 13

// charAt nümunəsi
const text = 'Salam';
console.log(text.charAt(0)); // 'S'
console.log(text.charAt(4)); // 'm'
console.log(text.charAt(10)); // ''
// Çıxış:
// S
// m
//

// substring nümunəsi
const text = 'Salam, Dünya!';
console.log(text.substring(0, 5)); // 'Salam'
console.log(text.substring(7)); // 'Dünya!'
console.log(text.substring(7, 12)); // 'Dünya'
// Çıxış:
// Salam
// Dünya!
// Dünya

// replace nümunəsi
const text = 'Salam, Dünya!';
console.log(text.replace('Dünya', ' Dünya 2025')); // 'Salam,  Dünya 2025!'
console.log(text.replace('a', 'A')); // 'SAlam, Dünya!'
// Çıxış:
// Salam,  Dünya 2025!
// SAlam, Dünya!

// split nümunəsi
const text = 'Salam, Dünya!';
console.log(text.split(' ')); // ['Salam,', 'Dünya!']
console.log(text.split(',')); // ['Salam', ' Dünya!']
console.log(text.split('', 3)); // ['S', 'a', 'l']
// Çıxış:
// ['Salam,', 'Dünya!']
// ['Salam', ' Dünya!']
// ['S', 'a', 'l']

// toUpperCase və toLowerCase nümunəsi
const text = 'Salam, Dünya!';
console.log(text.toUpperCase()); // 'SALAM, DÜNYA!'
console.log(text.toLowerCase()); // 'salam, dünya!'
// Çıxış:
// SALAM, DÜNYA!
// salam, dünya!

// trim nümunəsi
const text = '   Salam, Dünya!   ';
console.log(text.trim()); // 'Salam, Dünya!'
console.log(text.trim().length); // 13
// Çıxış:
// Salam, Dünya!
// 13

// indexOf və lastIndexOf nümunəsi
const text = 'Salam, salam, dünya!';
console.log(text.indexOf('salam')); // 7
console.log(text.lastIndexOf('salam')); // 7
console.log(text.indexOf('abc')); // -1
// Çıxış:
// 7
// 7
// -1

// slice nümunəsi
const text = 'Salam, Dünya!';
console.log(text.slice(0, 5)); // 'Salam'
console.log(text.slice(7)); // 'Dünya!'
console.log(text.slice(-6)); // 'Dünya!'
// Çıxış:
// Salam
// Dünya!
// Dünya!

// includes nümunəsi
const text = 'Salam, Dünya!';
console.log(text.includes('Salam')); // true
console.log(text.includes('salam')); // true
console.log(text.includes('abc')); // false
// Çıxış:
// true
// false
// false

// startsWith və endsWith nümunəsi
const text = 'Salam, Dünya!';
console.log(text.startsWith('Salam')); // true
console.log(text.startsWith('salam')); // false
console.log(text.endsWith('Dünya!')); // true
console.log(text.endsWith('dunya')); // false
// Çıxış:
// true
// false
// true
// false

// repeat nümunəsi
const text = 'Salam! ';
console.log(text.repeat(3)); // 'Salam! Salam! Salam! '
// Çıxış:
// Salam! Salam! Salam!

// concat nümunəsi
const text1 = 'Salam';
const text2 = 'Dünya!';
console.log(text1.concat(', ', text2)); // 'Salam, Dünya!'
// Çıxış:
// Salam, Dünya!

// match nümunəsi
const text = 'Salam, dünya 123 dünya!';
console.log(text.match('dünya')); // ['dünya']
console.log(text.match(/d+/g)); // ['123']
// Çıxış:
// ['dünya']
// ['123']

// search nümunəsi
const text = 'Salam, dünya!';
console.log(text.search('dünya')); // 7
console.log(text.search('abc')); // -1
// Çıxış:
// 7
// -1

// replaceAll nümunəsi
const text = 'Salam, dünya, dünya!';
console.log(text.replaceAll('dünya', 'DİNYA')); // 'Salam, DİNYA, DİNYA!'
// Çıxış:
// Salam, DİNYA, DİNYA!

// Səhvə yol açan nümunə
const text = 'Salam, dünya!';
if (text.includes('SALAM')) {
  console.log('Tapıldı!');
} else {
  console.log('Tapılmadı!'); // Çıxış: Tapılmadı!
}
// Düzgün yol
if (text.toLowerCase().includes('salam')) {
  console.log('Tapıldı!'); // Çıxış: Tapıldı!
}
// Çıxış:
// Tapılmadı!
// Tapıldı!

