// length example
const text = 'Hello, World!';
console.log(text.length); // 13
// Output:
// 13

// charAt example
const text = 'Hello';
console.log(text.charAt(0)); // 'H'
console.log(text.charAt(4)); // 'o'
console.log(text.charAt(10)); // ''
// Output:
// H
// o
//

// substring example
const text = 'Hello, World!';
console.log(text.substring(0, 5)); // 'Hello'
console.log(text.substring(7)); // 'World!'
console.log(text.substring(7, 12)); // 'World'
// Output:
// Hello
// World!
// World

// replace example
const text = 'Hello, World!';
console.log(text.replace('World', 'Earth')); // 'Hello, Earth!'
console.log(text.replace('l', 'L')); // 'HeLlo, World!'
// Output:
// Hello, Earth!
// HeLlo, World!

// split example
const text = 'Hello, World!';
console.log(text.split(' ')); // ['Hello,', 'World!']
console.log(text.split(',')); // ['Hello', ' World!']
console.log(text.split('', 3)); // ['H', 'e', 'l']
// Output:
// ['Hello,', 'World!']
// ['Hello', ' World!']
// ['H', 'e', 'l']

// toUpperCase and toLowerCase example
const text = 'Hello, World!';
console.log(text.toUpperCase()); // 'HELLO, WORLD!'
console.log(text.toLowerCase()); // 'hello, world!'
// Output:
// HELLO, WORLD!
// hello, world!

// trim example
const text = '   Hello, World!   ';
console.log(text.trim()); // 'Hello, World!'
console.log(text.trim().length); // 13
// Output:
// Hello, World!
// 13

// indexOf and lastIndexOf example
const text = 'Hello, hello, world!';
console.log(text.indexOf('hello')); // 7
console.log(text.lastIndexOf('hello')); // 7
console.log(text.indexOf('abc')); // -1
// Output:
// 7
// 7
// -1

// slice example
const text = 'Hello, World!';
console.log(text.slice(0, 5)); // 'Hello'
console.log(text.slice(7)); // 'World!'
console.log(text.slice(-6)); // 'World!'
// Output:
// Hello
// World!
// World!

// includes example
const text = 'Hello, World!';
console.log(text.includes('Hello')); // true
console.log(text.includes('world')); // false
console.log(text.includes('abc')); // false
// Output:
// true
// false
// false

// startsWith and endsWith example
const text = 'Hello, World!';
console.log(text.startsWith('Hello')); // true
console.log(text.startsWith('world')); // false
console.log(text.endsWith('World!')); // true
console.log(text.endsWith('world')); // false
// Output:
// true
// false
// true
// false

// repeat example
const text = 'Hello! ';
console.log(text.repeat(3)); // 'Hello! Hello! Hello! '
// Output:
// Hello! Hello! Hello!

// concat example
const text1 = 'Hello';
const text2 = 'World!';
console.log(text1.concat(', ', text2)); // 'Hello, World!'
// Output:
// Hello, World!

// match example
const text = '123, world, world!';
console.log(text.match('world')); // ['world']
console.log(text.match(/d+/g)); // ['123']
// Output:
// ['world']
// ['123']

// search example
const text = 'Hello, world!';
console.log(text.search('world')); // 7
console.log(text.search('abc')); // -1
// Output:
// 7
// -1

// replaceAll example
const text = 'Hello, world, world!';
console.log(text.replaceAll('world', 'Earth')); // 'Hello, Earth, Earth!'
// Output:
// Hello, Earth, Earth!

// Error-prone example
const text = 'Hello, world!';
if (text.includes('HELLO')) {
    console.log('Found!');
} else {
    console.log('Not found!'); // Output: Not found!
}
// Correct approach
if (text.toLowerCase().includes('hello')) {
    console.log('Found!'); // Output: Found!
}
// Output:
// Not found!
// Found!

